import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Date;

public class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateTypeMock;

    @BeforeEach
    public void setUp() {
        dateTypeMock = mock(DefaultDateTypeAdapter.DateType.class);
        adapter = new DefaultDateTypeAdapter<>(dateTypeMock, "yyyy-MM-dd");
    }

    @Test
    public void testRead_NullToken_ReturnsNull() throws IOException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.NULL);

        Date result = adapter.read(in);

        verify(in).nextNull();
        assertNull(result);
    }

    @Test
    public void testRead_ValidDate_DeserializeCalled() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.STRING);

        // We will mock the private method deserializeToDate to return a Date
        Method deserializeToDateMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        Date expectedDate = new Date();

        // Spy adapter to mock private method
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);
        doReturn(expectedDate).when(spyAdapter).deserializeToDate(in);

        when(dateTypeMock.deserialize(expectedDate)).thenReturn(expectedDate);

        Date result = spyAdapter.read(in);

        verify(spyAdapter).deserializeToDate(in);
        verify(dateTypeMock).deserialize(expectedDate);
        assertEquals(expectedDate, result);
    }
}
